def find_fraction(n):
    if n <= 3:
        return "NO"
    else:
        k = n - 2
        return "YES\n" + str(k) + "\n" + "1 " + str(n - 1) + "\n" + "1 " + str(n)


n = int(input())
print(find_fraction(n))
